import React, { useRef, useState, useEffect } from "react";

const EllipsisCell = ({ value, maxWidth = "200px" }) => {
  const spanRef = useRef(null);
  const [isTruncated, setIsTruncated] = useState(false);

  useEffect(() => {
    const el = spanRef.current;
    if (el) {
      setIsTruncated(el.scrollWidth > el.clientWidth);
    }
  }, [value]);

  return (
    <span
      ref={spanRef}
      style={{
        display: "block",
        whiteSpace: "nowrap",
        overflow: "hidden",
        textOverflow: "ellipsis",
        maxWidth,
      }}
      title={isTruncated ? value : undefined} // seulement si tronqué
    >
      {value}
    </span>
  );
};

export default EllipsisCell;

// src/utils/formatters.js

/**
 * Formate un nombre en euros selon la convention française.
 * @param {number} value - Le montant à formater
 * @returns {string} Montant formaté avec le symbole €
 */
export const formatCurrency = (value) => {
  if (value === null || value === undefined || value === "") return "";
  const number = Number(value);
  if (isNaN(number)) return "";
  return number.toLocaleString("fr-FR", {
    style: "currency",
    currency: "EUR",
  });
};

/**
 * Formate une date en JJ/MM/AAAA selon la convention française.
 * @param {string|Date} value - La date à formater
 * @returns {string} Date formatée ou chaîne vide si invalide
 */
export const formatDate = (value) => {
  if (!value) return "";
  const date = new Date(value);
  if (isNaN(date.getTime())) return ""; // renvoie '' si date invalide
  return date.toLocaleDateString("fr-FR");
};

// src/constants/translations.js
export const FR = {
  status: {
    draft: 'Brouillon',
    sent: 'Envoyée',
    paid: 'Payée',
    cancelled: 'Annulée',
  },
  technicalStatus: {
    pending: 'En attente',
    received: 'Reçue',
    validated: 'Validée',
    rejected: 'Rejetée',
    error: 'Erreur',
  },
};

import React, { useEffect } from "react";
import { FR } from "../../constants/translations";

export default function TechnicalStatusCell({ row, invoiceService, onTechnicalStatusChange }) {
  const status = row.technical_status || "PENDING";
  const statusKey = status.toLowerCase();
  const label = FR.technicalStatus[statusKey] || statusKey;

  let color = "gray";
  if (statusKey === "received") color = "green";
  else if (statusKey === "validated") color = "blue";
  else if (statusKey === "rejected") color = "red";
  else if (statusKey === "error") color = "darkred";

  useEffect(() => {
    if (!row.submissionId) return;
    if (["validated", "rejected"].includes(statusKey)) return;

    let isMounted = true;
    const intervalTime = 2000;

    const timer = setInterval(async () => {
      if (!isMounted) return;

      try {
        const pdpStatus = await invoiceService.pollInvoiceStatusPDP(
          row.submissionId,
          intervalTime,
          20000
        );

        if (pdpStatus?.technicalStatus) {
          onTechnicalStatusChange?.(row.id, pdpStatus.technicalStatus);

          if (["validated", "rejected"].includes(pdpStatus.technicalStatus.toLowerCase())) {
            clearInterval(timer);
          }
        }
      } catch (err) {
        console.error("Erreur polling PDP:", err);
        clearInterval(timer);
      }
    }, intervalTime);

    // Première vérification immédiate
    (async () => {
      try {
        const pdpStatus = await invoiceService.pollInvoiceStatusPDP(
          row.submissionId,
          intervalTime,
          20000
        );
        if (pdpStatus?.technicalStatus) {
          onTechnicalStatusChange?.(row.id, pdpStatus.technicalStatus);
        }
      } catch (err) {
        console.error("Erreur polling PDP initial :", err);
      }
    })();

    return () => {
      isMounted = false;
      clearInterval(timer);
    };
  }, [row.submissionId, statusKey, invoiceService, onTechnicalStatusChange, row.id]);

  return (
    <div style={{ textAlign: "center" }}>
      <span
        style={{
          display: "inline-block",
          padding: "2px 6px",
          borderRadius: "4px",
          backgroundColor: color,
          color: "white",
          fontWeight: 500,
          fontSize: "0.85em",
        }}
      >
        {label}
      </span>
    </div>
  );
}

import React, { useState, useEffect } from "react";
import { BUSINESS_STATUSES } from '../../constants/businessStatuses';

export default function BusinessStatusCell({ row, getStatusComment }) {
  const [status, setStatus] = useState({
    code: row.business_status || 100,
    label: BUSINESS_STATUSES[row.business_status || 100]?.label || 'Non renseigné',
  });

  const [comment, setComment] = useState(null);

  // Sync status si row.business_status change
  useEffect(() => {
    setStatus({
      code: row.business_status || 100,
      label: BUSINESS_STATUSES[row.business_status || 100]?.label || 'Non renseigné',
    });

    // On récupère le commentaire si la fonction est passée
    if (getStatusComment) {
      getStatusComment().then(c => setComment(c));
    }
  }, [row.business_status, getStatusComment]);

  const bgColor = BUSINESS_STATUSES[status.code]?.color || 'gray';

  return (
    <div style={{ textAlign: "center" }}>
      <span
        style={{
          display: "inline-block",
          padding: "2px 6px",
          borderRadius: "4px",
          backgroundColor: bgColor,
          color: 'white',
          fontWeight: 500,
          fontSize: "0.85em",
          cursor: row.submission_id ? 'pointer' : 'default',
        }}
        title={comment || status.label} // affiche le commentaire si existant
      >
        {status.label}
      </span>
    </div>
  );
}

// src/utils/downloadFile.js
export async function downloadFile(url, filename) {
  try {
    const res = await fetch(url);
    if (!res.ok) throw new Error(`Erreur serveur (${res.status})`);

    const blob = await res.blob();
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(link.href);

    console.log(`✅ Fichier téléchargé : ${filename}`);
  } catch (err) {
    console.error(`❌ Erreur téléchargement fichier : ${err.message}`);
    throw err;
  }
}

// frontend/src/utils/validators/email.js

/**
 * Vérifie si une chaîne est un email valide
 * @param {string} email
 * @returns {string|null} message d'erreur ou null si valide
 */
export function validateEmail(email) {
  if (!email || !email.trim()) return "L'email est obligatoire";

  // regex simple mais efficace pour la plupart des emails
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  if (!emailRegex.test(email)) return "Format d'email invalide";

  return null; // valide
}

/**
 * Vérifie si une chaîne est un email facultatif mais valide si renseigné
 * @param {string} email
 * @returns {string|null}
 */
export function validateOptionalEmail(email) {
  if (!email || !email.trim()) return null; // vide = ok
  return validateEmail(email);
}

import React, { useState, useEffect } from 'react';
import { Modal, Button, Form, Alert } from 'react-bootstrap';
import { validateEmail } from '../../utils/validators/email';

const EmailModal = ({ show, onClose, onSend, defaultValues }) => {
  const [to, setTo] = useState(defaultValues.to || '');
  const [subject, setSubject] = useState(defaultValues.subject || '');
  const [message, setMessage] = useState(defaultValues.message || '');
  const [error, setError] = useState(null);

  useEffect(() => {
    setTo(defaultValues.to || '');
    setSubject(defaultValues.subject || '');
    setMessage(defaultValues.message || '');
    setError(validateEmail(defaultValues.to || ''));
  }, [defaultValues, show]);

  const handleSubmit = () => {
    const validationError = validateEmail(to);
    if (validationError) {
      setError(validationError);
      return;
    }

    onSend({ to, subject, message });
    onClose();
  };

  const emailHasError = !!error;

  return (
    <Modal show={show} onHide={onClose} centered>
      <Modal.Header closeButton>
        <Modal.Title>✉️ Envoyer la facture par email</Modal.Title>
      </Modal.Header>

      <Modal.Body>
        {emailHasError && (
          <Alert variant="danger" className="mb-3">
            {error}
          </Alert>
        )}

        <Form>
          <Form.Group className="mb-3" controlId="emailTo">
            <Form.Label>Destinataire</Form.Label>
            <Form.Control
              type="email"
              value={to}
              onChange={(e) => {
                setTo(e.target.value);
                const validationError = validateEmail(e.target.value);
                setError(validationError);
              }}
              placeholder="exemple@client.fr"
              isInvalid={emailHasError} 
            />
            <Form.Control.Feedback type="invalid">
              {error || 'Adresse email invalide.'}
            </Form.Control.Feedback>
          </Form.Group>

          <Form.Group className="mb-3">
            <Form.Label>Sujet</Form.Label>
            <Form.Control
              type="text"
              value={subject}
              onChange={(e) => setSubject(e.target.value)}
            />
          </Form.Group>

          <Form.Group>
            <Form.Label>Message</Form.Label>
            <Form.Control
              as="textarea"
              rows={6}
              value={message}
              onChange={(e) => setMessage(e.target.value)}
            />
          </Form.Group>
        </Form>
      </Modal.Body>

      <Modal.Footer>
        <Button variant="secondary" onClick={onClose}>
          Annuler
        </Button>
        <Button
          variant="primary"
          onClick={handleSubmit}
          disabled={!!validateEmail(to)} 
        >
          Envoyer
        </Button>
      </Modal.Footer>
    </Modal>
  );
};

export default EmailModal;

