        show={showModal}
        onClose={() => setShowModal(false)}
        onSend={handleSend}
        defaultValues={defaultValues}
      />
    </>
  );
}

import { useAuth0 } from "@auth0/auth0-react";
import { useCallback } from "react";
import { getEnv } from "@/utils/getEnv";

export function useAuth() {
  const { getAccessTokenSilently } = useAuth0();

  const getToken = useCallback(async () => {
    try {
      const env = getEnv(); 
      const audience = env.VITE_AUTH0_AUDIENCE;

      const token = await getAccessTokenSilently({
        authorizationParams: { audience },
      });

      // Vérification du format du token
      const parts = token.split(".");
      if (parts.length === 5) {
        console.warn("[Auth] Format JWE (token chiffré) ⚠️");
      } else if (parts.length !== 3) {
        console.warn("[Auth] Format token inattendu ⚠️");
      }

      return token;
    } catch (err) {
      console.error("Impossible de récupérer le token", err);
      throw err;
    }
  }, [getAccessTokenSilently]);

  return { getToken };
}

import { useMemo } from "react";
import { useAuth } from "@/hooks/useAuth";
import { getEnv } from "@/utils/getEnv"; 

const env = getEnv();
const API_ROOT = (env.VITE_API_URL || 'http://localhost:8080').replace(/\/$/, '');
const API_BASE = `${API_ROOT}/api/sellers`;

console.log("API_BASE sellers =", API_BASE);

export function useSellerService() {
  const { getToken } = useAuth();

  return useMemo(() => {
    const request = async (url, options = {}) => {
      const token = await getToken();
      const res = await fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          Authorization: `Bearer ${token}`,
        },
      });
      const text = await res.text();

      if (!res.ok) {
        throw new Error(`Erreur ${res.status}: ${text}`);
      }

      try {
        return JSON.parse(text);
      } catch {
        return true; // pour les DELETE qui ne renvoient rien
      }
    };

    return {
      fetchMySeller: () => request(`${API_BASE}/me`),
      createSeller: (data) =>
        request(API_BASE, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(data),
        }),
      updateSeller: (id, data) =>
        request(`${API_BASE}/${id}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(data),
        }),
      deleteSeller: () => request(API_BASE, { method: "DELETE" }),
      checkIdentifier: (identifier, sellerId) =>
        request(`${API_BASE}/check-identifier?identifier=${identifier}${sellerId ? `&id=${sellerId}` : ''}`),
      testSmtpResend: (smtpData) =>
        request(`${API_BASE}/smtp/test-resend`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(smtpData),
        }),
    };
  }, [getToken]);
}

import { useEffect, useState } from "react";
import { useSellerService } from "@/services/sellers";

/**
 * Hook personnalisé pour récupérer les informations du vendeur connecté.
 * Renvoie le plan, l'état d'activation SMTP et l'objet vendeur complet.
 */
export function useSellerInfo() {
  const sellerService = useSellerService();

  const [seller, setSeller] = useState(null);
  const [sellerPlan, setSellerPlan] = useState("essentiel");
  const [sellerActive, setSellerActive] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchSellerInfo = async () => {
      setIsLoading(true);
      setError(null);
      try {
        const fetchedSeller = await sellerService.fetchMySeller();
        console.log("Seller raw from service:", fetchedSeller);

        setSeller(fetchedSeller);

        // Plan principal du vendeur
        const plan = fetchedSeller?.plan || "essentiel";
        setSellerPlan(plan);

        // L'active correspond au SMTP actif
        const isActive = fetchedSeller?.smtp?.active === true;
        setSellerActive(isActive);

        console.log("Seller plan:", plan, "Active:", isActive);
      } catch (err) {
        console.error("Impossible de récupérer le vendeur :", err);
        setError(err);
        setSellerPlan("essentiel");
        setSellerActive(false);
      } finally {
        setIsLoading(false);
      }
    };

    fetchSellerInfo();
  }, [sellerService]);

  return { seller, sellerPlan, sellerActive, isLoading, error };
}

